nta.declaration:
// ============================================================
// Continuous-Flow Autonomous Intersection Management System
// Critical-Zone Time-Slot Reservation Model
// Author: Daniel Chidi Chimezie
// Project: Autonomous Intersection Management
//
// Main modelling goals:
// 1. Continuous traffic flow: no complete vehicle stop.
// 2. Collision freedom: no two vehicles occupy the same critical zone.
// 3. Reservation validity: vehicle enters a zone only with valid reservation.
// 4. Emergency vehicle priority through dynamic rescheduling.
// 5. Deadlock freedom.
// ============================================================


// =======================
// 1. CONSTANTS
// =======================

const int N = 3;                 // number of vehicles in the model
const int Z = 2;                 // number of critical zones
const int NONE = -1;             // no owner for a critical zone

const int MIN_SPEED = 1;         // lowest allowed moving speed
const int NORMAL_SPEED = 2;      // default moving speed
const int FAST_SPEED = 3;        // priority/emergency speed

const int REQUEST_DELAY = 1;     // abstract time before request is made
const int APPROACH_TIME = 1;     // abstract time from grant to zone entry
const int CROSSING_TIME = 1;     // abstract time spent inside a critical zone


// =======================
// 2. CLOCKS
// =======================

clock t[N];                      // one local clock per vehicle


// =======================
// 3. VEHICLE DATA
// =======================

// Current abstract vehicle speed.
// Important: speed must never be 0 in this continuous-flow model.
int speed[N] = {NORMAL_SPEED, NORMAL_SPEED, NORMAL_SPEED};

// Route abstraction:
// routeZone[i] is the critical zone required by vehicle i.
// Vehicle 0 and vehicle 1 both need CZ0.
// Vehicle 2 needs CZ1.
// This creates a useful conflict case for testing emergency priority.
int routeZone[N] = {0, 0, 1};

// Emergency setting:
// Vehicle 1 is the emergency vehicle.
bool isEmergency[N] = {false, true, false};


// =======================
// 4. RESERVATION STATE
// =======================

// zoneOwner[z] stores which vehicle currently owns critical zone z.
// NONE means the zone is free.
int zoneOwner[Z] = {NONE, NONE};

// reservationValid[i] is true if vehicle i currently has a valid reservation.
bool reservationValid[N] = {false, false, false};

// inZone[i] is true if vehicle i is physically inside its critical zone.
bool inZone[N] = {false, false, false};

// crossed[i] is true after vehicle i has left the intersection.
bool crossed[N] = {false, false, false};


// =======================
// 5. MONITORING FLAGS
// =======================

bool priorityGiven = false;             // true when emergency priority has been granted
bool recalculationTriggered = false;    // true when a reservation/speed recalculation occurs
bool conflictDetected = false;          // true if reservation conflict was detected


// =======================
// 6. SYNCHRONISATION CHANNELS
// =======================

chan request[N];        // vehicle requests reservation
chan grant[N];          // controller grants reservation
chan enterZone[N];      // vehicle enters critical zone
chan leaveZone[N];      // vehicle leaves critical zone


// =======================
// 7. HELPER FUNCTIONS
// =======================

// Return true if vehicle i can reserve its required critical zone.
bool canReserve(int i)
{
    int z = routeZone[i];

    // Case 1: zone is free.
    if (zoneOwner[z] == NONE)
        return true;

    // Case 2: vehicle already owns the zone.
    if (zoneOwner[z] == i)
        return true;

    // Case 3: emergency vehicle may dynamically reschedule another vehicle,
    // but only if the current owner is not already inside the critical zone.
    if (isEmergency[i] && !inZone[zoneOwner[z]])
        return true;

    return false;
}


// Assign reservation to vehicle i.
void reserveFor(int i)
{
    int z = routeZone[i];

    conflictDetected = false;

    // Emergency dynamic rescheduling:
    // If another vehicle owns this zone but is not yet inside it,
    // its reservation is invalidated and it must request again.
    // It is NOT stopped. Its speed becomes MIN_SPEED, meaning slow movement.
    if (zoneOwner[z] != NONE && zoneOwner[z] != i)
    {
        reservationValid[zoneOwner[z]] = false;
        speed[zoneOwner[z]] = MIN_SPEED;
        recalculationTriggered = true;
        conflictDetected = true;
    }

    zoneOwner[z] = i;
    reservationValid[i] = true;

    if (isEmergency[i])
    {
        priorityGiven = true;
        speed[i] = FAST_SPEED;
    }
    else
    {
        speed[i] = NORMAL_SPEED;
    }
}


// Release the reservation of vehicle i after it exits the critical zone.
void releaseFor(int i)
{
    int z = routeZone[i];

    if (zoneOwner[z] == i)
        zoneOwner[z] = NONE;

    reservationValid[i] = false;
    inZone[i] = false;
    crossed[i] = true;
    speed[i] = NORMAL_SPEED;
}


// Safety function:
// Returns true when no two vehicles are inside the same critical zone.
bool noCollision()
{
    return !(
        (inZone[0] && inZone[1] && routeZone[0] == routeZone[1]) ||
        (inZone[0] && inZone[2] && routeZone[0] == routeZone[2]) ||
        (inZone[1] && inZone[2] && routeZone[1] == routeZone[2])
    );
}


// Continuous-flow function:
// Returns true when all vehicles have speed greater than zero.
bool allSpeedPositive()
{
    return speed[0] > 0 && speed[1] > 0 && speed[2] > 0;
}


// Reservation-validity function:
// Returns true when every vehicle inside a zone has a valid reservation.
bool reservationSafety()
{
    return
        (!inZone[0] || reservationValid[0]) &&
        (!inZone[1] || reservationValid[1]) &&
        (!inZone[2] || reservationValid[2]);
}


// Liveness helper:
// Returns true when every vehicle has crossed the intersection.
bool allVehiclesCrossed()
{
    return crossed[0] && crossed[1] && crossed[2];
}

template.declaration:
// ============================================================
// Vehicle template
// Parameter: int id
//
// Vehicle states:
// Idle -> Requesting -> MovingToZone -> InCriticalZone -> Exited
//
// Important:
// There is deliberately no STOP state.
// If a vehicle loses its reservation due to emergency priority,
// it returns to Requesting while moving at MIN_SPEED.
// ============================================================

// ============================================================
// Controller template
//
// The controller receives reservation requests, checks whether the
// requested critical zone can be reserved, assigns reservations,
// and grants movement commands.
//
// Emergency vehicle priority:
// If the requesting vehicle is emergency and the zone is owned by a
// vehicle that is not yet inside the critical zone, the controller
// dynamically reschedules the old owner.
// ============================================================

int pending = 0;

nta.system:
// ============================================================
// System declarations
// Paste this section into UPPAAL's "System declarations" field
// if you are building the model manually.
// ============================================================

V0 = Vehicle(0);
V1 = Vehicle(1);
V2 = Vehicle(2);

C = Controller();

system V0, V1, V2, C;
